-- Tighten the Neon Sign outer glow. The original 4px + 10px filter
-- drop-shadow stack from 0087 read as a wide bloom that pushed past
-- neighboring chat text. 2px + 5px keeps the lit-tube feel but
-- doesn't blanket the surrounding line. Inner text-shadow stays
-- tight at 2/6/12 — that's the close hug on the glyph edges.

UPDATE `name_styles`
   SET `style_css` = '.ns-neon-sign { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); animation: ns-neon-sign 7s step-end infinite; } @keyframes ns-neon-sign { 0%, 6.9% { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); } 7%, 7.25% { color: var(--user-color-2, #8a8a8a); text-shadow: 0 0 1px var(--user-outline, #555); filter: none; } 7.3%, 23.4% { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); } 23.5%, 23.6% { color: var(--user-color-2, #8a8a8a); text-shadow: 0 0 1px var(--user-outline, #555); filter: none; } 23.7%, 23.8% { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); } 23.9%, 24% { color: var(--user-color-2, #8a8a8a); text-shadow: 0 0 1px var(--user-outline, #555); filter: none; } 24.1%, 57.9% { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); } 58%, 58.4% { color: var(--user-color-2, #8a8a8a); text-shadow: 0 0 1px var(--user-outline, #555); filter: none; } 58.5%, 100% { color: var(--user-color-1, #ffe0e8); text-shadow: 0 0 2px var(--user-glow, #ff1493), 0 0 6px var(--user-glow, #ff1493), 0 0 12px var(--user-glow, rgba(255,20,147,0.85)); filter: drop-shadow(0 0 2px var(--user-glow, rgba(255,20,147,0.9))) drop-shadow(0 0 5px var(--user-glow, rgba(255,20,147,0.55))); } }'
 WHERE `key` = 'neon_sign';
